create extension if not exists pgcrypto;
create type user_account_status as enum ('pending_review','approved_affiliate','rejected_pending_deletion','deleted','admin');
create type application_status as enum ('pending_review','approved','declined','deleted_or_anonymised');
create type affiliate_status as enum ('active','paused','suspended','removed');
create type lead_status as enum ('new_enquiry','qualified','discovery_booked','quoted','won','lost','rejected','not_commissionable');
create type commission_status as enum ('estimated','pending','approved','paid','cancelled','adjusted');
create table app_users(id uuid primary key references auth.users(id) on delete cascade,email text unique not null,role text not null default 'applicant',account_status user_account_status not null default 'pending_review',created_at timestamptz not null default now(),deleted_at timestamptz);
create table partner_applications(id uuid primary key default gen_random_uuid(),user_id uuid references app_users(id) on delete cascade,first_name text not null,surname text not null,business_name text not null,email text not null,phone text not null,website_url text,social_links text,google_business_url text,client_types text not null,motivation text not null,status application_status not null default 'pending_review',rejection_reason text,submitted_at timestamptz not null default now(),reviewed_at timestamptz,reviewed_by uuid references app_users(id),deletion_scheduled_at timestamptz,internal_notes text);
create table affiliates(id uuid primary key default gen_random_uuid(),user_id uuid unique references app_users(id) on delete cascade,affiliate_code text unique not null,display_name text not null,status affiliate_status not null default 'active',commission_build_percent numeric(5,2) default 10,commission_recurring_percent numeric(5,2) default 5,approved_at timestamptz,approved_by uuid references app_users(id));
create table tracking_links(id uuid primary key default gen_random_uuid(),affiliate_id uuid not null references affiliates(id) on delete cascade,tracking_token text not null,destination_url text not null,private_reference text not null,channel text not null,notes text,custom_alias text,is_active boolean not null default true,created_at timestamptz not null default now(),expires_at timestamptz,unique(affiliate_id,tracking_token));
create table click_events(id uuid primary key default gen_random_uuid(),tracking_link_id uuid references tracking_links(id) on delete set null,affiliate_id uuid references affiliates(id) on delete set null,session_id text not null,timestamp timestamptz not null default now(),landing_page text,referrer text,device_type text,browser text,country text,region text,ip_hash text,user_agent_hash text);
create table referral_sessions(id uuid primary key default gen_random_uuid(),session_id text unique not null,affiliate_id uuid references affiliates(id) on delete set null,tracking_link_id uuid references tracking_links(id) on delete set null,first_click_at timestamptz not null default now(),last_click_at timestamptz not null default now(),attribution_expires_at timestamptz not null);
create table leads(id uuid primary key default gen_random_uuid(),lead_number bigint generated always as identity,affiliate_id uuid references affiliates(id) on delete set null,tracking_link_id uuid references tracking_links(id) on delete set null,session_id text,client_name text,client_business text,client_email text,client_phone text,service_interest text,message text,status lead_status not null default 'new_enquiry',created_at timestamptz not null default now(),privacy_consent boolean not null default false,manual_attribution_reason text,fraud_flag boolean not null default false);
create table deals(id uuid primary key default gen_random_uuid(),lead_id uuid references leads(id) on delete cascade,affiliate_id uuid references affiliates(id) on delete set null,service_type text,quote_amount numeric(12,2),build_fee numeric(12,2),recurring_fee numeric(12,2),status text not null default 'in_review',won_at timestamptz,lost_reason text);
create table payments(id uuid primary key default gen_random_uuid(),deal_id uuid references deals(id) on delete cascade,amount_received numeric(12,2) not null,payment_type text,payment_date date,payment_status text not null default 'pending');
create table commissions(id uuid primary key default gen_random_uuid(),affiliate_id uuid references affiliates(id) on delete cascade,deal_id uuid references deals(id) on delete cascade,payment_id uuid references payments(id) on delete set null,commission_type text not null,commission_base_amount numeric(12,2) not null,commission_rate numeric(5,2) not null,commission_amount numeric(12,2) not null,status commission_status not null default 'estimated',due_date date,paid_at timestamptz);
create table audit_logs(id uuid primary key default gen_random_uuid(),actor_user_id uuid references app_users(id),action_type text not null,entity_type text not null,entity_id text not null,previous_value jsonb,new_value jsonb,timestamp timestamptz not null default now());
alter table app_users enable row level security;alter table partner_applications enable row level security;alter table affiliates enable row level security;alter table tracking_links enable row level security;alter table click_events enable row level security;alter table referral_sessions enable row level security;alter table leads enable row level security;alter table deals enable row level security;alter table payments enable row level security;alter table commissions enable row level security;alter table audit_logs enable row level security;
create policy "users can read own profile" on app_users for select using (auth.uid()=id);
create policy "applicants read own application" on partner_applications for select using (auth.uid()=user_id);
create policy "affiliates read own profile" on affiliates for select using (auth.uid()=user_id);
create policy "affiliates read own links" on tracking_links for select using (affiliate_id in (select id from affiliates where user_id=auth.uid()));
create policy "affiliates read own clicks" on click_events for select using (affiliate_id in (select id from affiliates where user_id=auth.uid()));
create policy "affiliates read own leads" on leads for select using (affiliate_id in (select id from affiliates where user_id=auth.uid()));
create policy "affiliates read own commissions" on commissions for select using (affiliate_id in (select id from affiliates where user_id=auth.uid()));
create or replace function is_admin() returns boolean language sql stable as $$ select exists(select 1 from app_users where id=auth.uid() and (role='admin' or account_status='admin')) $$;
create policy "admins all users" on app_users for all using (is_admin()) with check (is_admin());
create policy "admins all applications" on partner_applications for all using (is_admin()) with check (is_admin());
create policy "admins all affiliates" on affiliates for all using (is_admin()) with check (is_admin());
create policy "admins all links" on tracking_links for all using (is_admin()) with check (is_admin());
create policy "admins all clicks" on click_events for all using (is_admin()) with check (is_admin());
create policy "admins all sessions" on referral_sessions for all using (is_admin()) with check (is_admin());
create policy "admins all leads" on leads for all using (is_admin()) with check (is_admin());
create policy "admins all deals" on deals for all using (is_admin()) with check (is_admin());
create policy "admins all payments" on payments for all using (is_admin()) with check (is_admin());
create policy "admins all commissions" on commissions for all using (is_admin()) with check (is_admin());
create policy "admins all audit" on audit_logs for all using (is_admin()) with check (is_admin());
create index on tracking_links(affiliate_id,tracking_token);create index on click_events(affiliate_id,timestamp);create index on leads(affiliate_id,status);create index on commissions(affiliate_id,status);
